import{_ as t,o as a,c as o,a3 as i}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"105. Interaction With The Safe Patient Care Act","description":"","frontmatter":{"title":"105. Interaction With The Safe Patient Care Act","eba":"Nurses and Midwives 2024-2028","topics":["staffing"]},"headers":[],"relativePath":"ebas/nurses-midwives/safe-patient-care/105-interaction-with-the-safe-patient-care-act.md","filePath":"ebas/nurses-midwives/safe-patient-care/105-interaction-with-the-safe-patient-care-act.md"}'),r={name:"ebas/nurses-midwives/safe-patient-care/105-interaction-with-the-safe-patient-care-act.md"};function n(s,e,c,h,p,l){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="_105-interaction-with-the-safe-patient-care-act" tabindex="-1">105. Interaction With The Safe Patient Care Act <a class="header-anchor" href="#_105-interaction-with-the-safe-patient-care-act" aria-label="Permalink to &quot;105. Interaction With The Safe Patient Care Act&quot;">​</a></h1><p><strong>105.1</strong> The provisions in clauses 105.3 to 105.6 (inclusive) below will commence operation if either of the following conditions are met:</p><p><strong>(a)</strong> the Safe Patient Care Act is repealed or otherwise ceases to operate as a law of the State of Victoria; or</p><p><strong>(b)</strong> a Care/Ratio Detriment Notice comes into effect pursuant to subclause 105.2(e) below.</p><p>In this clause 105, Incorporation Date means the date on which either of the conditions in subclauses 105.1(a) or (b) are met.</p><p><strong>105.2</strong> Care/Ratio Detriment Notice</p><p><strong>(a)</strong> If the Secretary of the ANMF (Victorian Branch) (Secretary) is satisfied that the Safe Patient Care Act has been amended or its operation varied by reason of any Act or Subordinate Instrument in such a manner as to be likely to result in a detriment to the level of safe patient care and nurse/midwife to patient ratios (care/ratio change) facilitated by the Safe Patient Care Act, she/he may issue a notice (Care/Ratio Detriment Notice).</p><p><strong>(b)</strong> A Care/Ratio Detriment Notice will be filed with the Commission and served on the VHIA, the Department Head of DOH and each Employer to which this Agreement applies.</p><p><strong>(c)</strong> A Care/Ratio Detriment Notice must be filed and served within 60 days of the coming into effect of the care/ratio change concerned and must specify the care/ratio change.</p><p><strong>(d)</strong> A failure or deficiency in service under subclauses 105.2(b) or 105.2(e)(ii) will not affect the validity and effect of the Care/Ratio Detriment Notice or the withdrawal of that Notice if properly filed with the Commission.</p><p><strong>(e)</strong> The Care/Ratio Detriment Notice will come into effect as follows:</p><p><strong>(i)</strong> The Care/Ratio Detriment Notice will come into effect 7 days after it is filed with the Commission unless, during that 7 day period (Notification Period), the VHIA files with the Commission and serves on the Secretary, a consultation request. If a consultation request is served in the Notification Period, then subclause 105.2(e)(ii) will apply.</p><p><strong>(ii)</strong> Upon filing a consultation request pursuant to subclause 105.2(e)(i), a period of 14 days will be allowed for consultation to occur (Consultation Period). During the Consultation Period the Secretary or delegate and the VHIA will consult in good faith in relation to the care/ratio change and the Care/Ratio Detriment Notice. The Department Head or delegate of DOH may be involved in these consultations. The Secretary may withdraw the Care/Ratio Detriment Notice at any time during the Consultation Period by filing correspondence to this effect with the Commission and serving it on the VHIA, the Department Head of DOH and each Employer to which this Agreement applies. Unless withdrawn during the Consultation</p><p><a href="/eba/ebas/mental-health/schedules/01-list-of-employers.html">Appendix 1</a> – List of Employers 220</p><p><a href="/eba/ebas/mental-health/schedules/01-list-of-employers.html">Appendix 1</a> – List of Employers</p><p>Period, the Care/Ratio Detriment Notice will come into effect on the day after the end of the Consultation Period.</p><p><strong>(f)</strong> The Secretary in determining their satisfaction as to detriment under subclause 105.2(a) will have regard to the following:</p><p><strong>(i)</strong> any representation made by persons affected by the care/ratio impact change;</p><p><strong>(ii)</strong> the likely effect of the care/ratio impact change on the provision of safe patient care;</p><p><strong>(iii)</strong> the likely effect of the care/ratio impact change on nursing/midwifery workloads; and</p><p><strong>(iv)</strong> the purpose and reasons for the care/ratio impact change (if any) provided to the Parliament.</p><p><strong>(g)</strong> Nothing in clauses 105.1 or 105.2 or any act or failure to act under clauses</p><p><strong>105.1</strong> or 105.2 will be subject to the Dispute Resolution Procedure in this Agreement or otherwise be subject to review.</p><p><strong>105.3</strong> If either of the conditions in subclauses 105.1(a) or (b) are met:</p><p><strong>(a)</strong> sections 3, 4 and 5 of Part 1, Part 2 and Schedules 1, 2 and 3 of the Safe Patient Care Act and any associated regulations as in force immediately prior to:</p><p><strong>(i)</strong> the date the Safe Patient Care Act is repealed or otherwise ceases to operate as a law of the State of Victoria; or</p><p><strong>(ii)</strong> the date of the care/ratio change in respect of which a Care/Ratio Detriment Notice was issued under subclause 105.2(a),</p><p>will be incorporated as terms of this Agreement with effect from the Incorporation Date;</p><p><strong>(b)</strong> the ratios in force by operation of any re-distribution or variation or agreement under Part 2 – Division 4 or by the operation of sections 47, 48 or 49 of the Safe Patient Care Act as in force immediately prior to:</p><p><strong>(i)</strong> the date the Safe Patient Care Act is repealed or otherwise ceases to operate as a law of the State of Victoria; or</p><p><strong>(ii)</strong> the date of the care/ratio change in respect of which a Care/Ratio Detriment Notice was issued under subclause 105.2(a),</p><p>will be incorporated as terms of this Agreement with effect from the Incorporation Date;</p><p><strong>(c)</strong> references in this Agreement to the Safe Patient Care Act, other than the references in <a href="/eba/ebas/allied-health/preliminary/4-definitions.html">clauses 4.4</a> and 6.4, and clause 105 (Interaction with the Safe Patient Care Act) are to be read as the Safe Patient Care Act as incorporated by subclauses 105.3(a) and 105.3(b) with effect from the Incorporation Date; and</p><p><strong>(d)</strong> the Agreement is to operate to the complete exclusion of any inconsistent State laws with effect from the Incorporation Date.</p><p><a href="/eba/ebas/mental-health/schedules/01-list-of-employers.html">Appendix 1</a> – List of Employers 221</p><p><a href="/eba/ebas/mental-health/schedules/01-list-of-employers.html">Appendix 1</a> – List of Employers</p><p><strong>105.4</strong> For the purposes of this clause 105, &#39;Safe Patient Care Act as incorporated&#39; means those parts of the Safe Patient Care Act and associated regulations incorporated pursuant to clause 105.3.</p><p><strong>105.5</strong> The terms of the Safe Patient Care Act as incorporated into this Agreement pursuant to clause 105.3, will operate in conjunction with the terms of the Agreement, provided that where there is an inconsistency between the Safe Patient Care Act as incorporated and other provisions of this Agreement, the terms of the Safe Patient Care Act as incorporated, will prevail.</p><p><strong>105.6</strong> Any dispute as to how any provision of the Safe Patient Care Act as incorporated, operates or operates in conjunction with the Agreement, may be progressed through <a href="/eba/ebas/nurses-midwives/consultation-disputes/13-dispute-resolution-procedure.html">clause 13</a> (Dispute Resolution Procedure) of this Agreement. In exercising its powers in relation to such a dispute under <a href="/eba/ebas/nurses-midwives/consultation-disputes/13-dispute-resolution-procedure.html">clause 13</a>, the Commission:</p><p><strong>(a)</strong> must take into account the objects of the Safe Patient Care Act as incorporated pursuant to clause 105.3;</p><p><strong>(b)</strong> may, if necessary, take into account the intention of Parliament as expressed in the explanatory memorandum to the Safe Patient Care (Nurse to Patient and Midwife to Patient Ratios) Bill 2005 (Vic); and</p><p><strong>(c)</strong> may only, if the dispute is in respect of a variation to the ratios made in accordance with the Safe Patient Care Act as incorporated by clause 105.3, consider whether consultation in good faith has occurred. Accordingly, clinical aspects of the variation remain the sole responsibility and accountability of the Employer and are not subject to consideration by the Commission.</p><p>Plain language terms: SPCA, Safe Patient Care Act, ratios law.</p>',43)])])}const u=t(r,[["render",n]]);export{d as __pageData,u as default};
